"use client";

import { useState } from "react";
import Link from "next/link";
import {
  ArrowLeft,
  HeartPulse,
  Activity,
  Building2,
  Users,
  TrendingUp,
  Clock,
  Stethoscope,
  Ambulance,
  Home,
  Sun,
  Brain,
  Eye,
  ChevronDown,
  ChevronRight,
  Truck,
  Wrench,
  Target,
  AlertCircle,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import {
  CORES_SAUDE_MUNICIPAL,
  UNIDADES_BASICAS_SAUDE,
  CASAS_ESPECIALIZADAS,
  UNIDADES_PRONTO_ATENDIMENTO,
  HOSPITAIS_MUNICIPAIS,
  SERVICOS_MOVEIS,
  INDICADORES_SAUDE_MUNICIPAL,
} from "@/lib/dados-saude-municipal";
import { CardUnidade } from "./components/CardUnidade";
import { CardUPA } from "./components/CardUPA";
import { CardHospital } from "./components/CardHospital";
import { CardServicoMovel } from "./components/CardServicoMovel";

export default function GestaoSaudeMunicipal() {
  const [abaPrincipal, setAbaPrincipal] = useState("atencao-basica");
  const [submenuUBS, setSubmenuUBS] = useState(true);
  const [submenuCasas, setSubmenuCasas] = useState(true);

  return (
    <main className="min-h-screen" style={{ backgroundColor: CORES_SAUDE_MUNICIPAL.fundo }}>
      {/* Header */}
      <header
        className="text-white shadow-lg sticky top-0 z-50"
        style={{
          background: `linear-gradient(135deg, ${CORES_SAUDE_MUNICIPAL.primaria} 0%, ${CORES_SAUDE_MUNICIPAL.terciaria} 100%)`,
        }}
      >
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/">
                <Button variant="ghost" size="icon" className="text-white hover:bg-white/20">
                  <ArrowLeft className="h-5 w-5" />
                </Button>
              </Link>
              <div className="flex items-center gap-3">
                <div className="p-2 bg-white/20 rounded-full">
                  <HeartPulse className="h-6 w-6" />
                </div>
                <div>
                  <h1 className="text-xl font-bold">Gestão da Saúde Municipal</h1>
                  <p className="text-sm opacity-90">Sistema Integrado de Saúde - SUS</p>
                </div>
              </div>
            </div>
            <Badge className="bg-white/20 text-white border-0">
              <Activity className="h-3 w-3 mr-1" />
              Online
            </Badge>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-6">
        {/* KPIs Principais */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          <Card className="border-l-4" style={{ borderLeftColor: CORES_SAUDE_MUNICIPAL.sucesso }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs text-slate-500">Cobertura AB</p>
                  <p className="text-xl font-bold" style={{ color: CORES_SAUDE_MUNICIPAL.primaria }}>
                    {INDICADORES_SAUDE_MUNICIPAL.coberturaAB}%
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.sucesso}20` }}>
                  <Users className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.sucesso }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_SAUDE_MUNICIPAL.info }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs text-slate-500">Atendimentos/Mês</p>
                  <p className="text-lg font-bold" style={{ color: CORES_SAUDE_MUNICIPAL.primaria }}>
                    {(INDICADORES_SAUDE_MUNICIPAL.atendimentosMes / 1000).toFixed(1)}k
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.info}20` }}>
                  <Activity className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.info }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_SAUDE_MUNICIPAL.destaque }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs text-slate-500">Satisfação</p>
                  <p className="text-xl font-bold" style={{ color: CORES_SAUDE_MUNICIPAL.primaria }}>
                    {INDICADORES_SAUDE_MUNICIPAL.satisfacaoUsuario}/5
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.destaque}20` }}>
                  <TrendingUp className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.destaque }} />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-l-4" style={{ borderLeftColor: CORES_SAUDE_MUNICIPAL.alerta }}>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs text-slate-500">Tempo Médio</p>
                  <p className="text-xl font-bold" style={{ color: CORES_SAUDE_MUNICIPAL.primaria }}>
                    {INDICADORES_SAUDE_MUNICIPAL.tempoEsperaMedia}min
                  </p>
                </div>
                <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.alerta}20` }}>
                  <Clock className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.alerta }} />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Abas Principais */}
        <Tabs value={abaPrincipal} onValueChange={setAbaPrincipal} className="space-y-4">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="atencao-basica" className="flex items-center gap-2 text-xs md:text-sm">
              <Stethoscope className="h-4 w-4" />
              <span className="hidden sm:inline">Atenção Básica</span>
              <span className="sm:hidden">Básica</span>
            </TabsTrigger>
            <TabsTrigger value="urgencia" className="flex items-center gap-2 text-xs md:text-sm">
              <AlertCircle className="h-4 w-4" />
              <span className="hidden sm:inline">Urgência</span>
              <span className="sm:hidden">Urg.</span>
            </TabsTrigger>
            <TabsTrigger value="hospital" className="flex items-center gap-2 text-xs md:text-sm">
              <Building2 className="h-4 w-4" />
              Hospital
            </TabsTrigger>
            <TabsTrigger value="moveis" className="flex items-center gap-2 text-xs md:text-sm">
              <Truck className="h-4 w-4" />
              <span className="hidden sm:inline">Móveis</span>
              <span className="sm:hidden">Móv.</span>
            </TabsTrigger>
          </TabsList>

          {/* ABA 1: ATENÇÃO BÁSICA */}
          <TabsContent value="atencao-basica" className="space-y-4">
            {/* Submenu UBS */}
            <Collapsible open={submenuUBS} onOpenChange={setSubmenuUBS}>
              <CollapsibleTrigger asChild>
                <Button variant="ghost" className="w-full flex items-center justify-between p-4 h-auto bg-white hover:bg-slate-50 border rounded-lg">
                  <div className="flex items-center gap-3">
                    <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.primaria}20` }}>
                      <Building2 className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.primaria }} />
                    </div>
                    <div className="text-left">
                      <h2 className="font-bold text-lg">Unidades Básicas de Saúde (UBS)</h2>
                      <p className="text-sm text-slate-500">{UNIDADES_BASICAS_SAUDE.length} unidades</p>
                    </div>
                  </div>
                  {submenuUBS ? <ChevronDown className="h-5 w-5" /> : <ChevronRight className="h-5 w-5" />}
                </Button>
              </CollapsibleTrigger>
              <CollapsibleContent className="mt-3">
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                  {UNIDADES_BASICAS_SAUDE.map((ubs) => (
                    <CardUnidade
                      key={ubs.id}
                      id={ubs.id}
                      nome={ubs.nome}
                      bairro={ubs.bairro}
                      endereco={ubs.endereco}
                      telefone={ubs.telefone}
                      horario={ubs.horario}
                      icone={<Building2 className="h-8 w-8 text-white" />}
                      cor={CORES_SAUDE_MUNICIPAL.primaria}
                      metas={{
                        cumprimento: ubs.metas.cumprimento,
                        atendidos: ubs.metas.atendidos,
                        total: ubs.metas.consultasMensais,
                      }}
                      secoes={ubs.secoes}
                      extraInfo={
                        <div className="flex gap-1 flex-wrap">
                          <Badge variant="outline" className="text-[9px]">{ubs.equipes} equipes</Badge>
                          <Badge variant="outline" className="text-[9px]">{ubs.agentesComunitarios} ACS</Badge>
                        </div>
                      }
                    />
                  ))}
                </div>
              </CollapsibleContent>
            </Collapsible>

            {/* Submenu Casas Especializadas */}
            <Collapsible open={submenuCasas} onOpenChange={setSubmenuCasas}>
              <CollapsibleTrigger asChild>
                <Button variant="ghost" className="w-full flex items-center justify-between p-4 h-auto bg-white hover:bg-slate-50 border rounded-lg">
                  <div className="flex items-center gap-3">
                    <div className="p-2 rounded-lg" style={{ backgroundColor: `${CORES_SAUDE_MUNICIPAL.terciaria}20` }}>
                      <Home className="h-5 w-5" style={{ color: CORES_SAUDE_MUNICIPAL.terciaria }} />
                    </div>
                    <div className="text-left">
                      <h2 className="font-bold text-lg">Casas Especializadas</h2>
                      <p className="text-sm text-slate-500">{CASAS_ESPECIALIZADAS.length} unidades especializadas</p>
                    </div>
                  </div>
                  {submenuCasas ? <ChevronDown className="h-5 w-5" /> : <ChevronRight className="h-5 w-5" />}
                </Button>
              </CollapsibleTrigger>
              <CollapsibleContent className="mt-3">
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                  {CASAS_ESPECIALIZADAS.map((casa) => (
                    <CardUnidade
                      key={casa.id}
                      id={casa.id}
                      nome={casa.nome}
                      bairro={casa.bairro}
                      endereco={casa.endereco}
                      telefone={casa.telefone}
                      horario={casa.horario}
                      icone={
                        casa.sigla === 'CEMO' ? <Eye className="h-8 w-8 text-white" /> :
                        casa.sigla === 'CASA DIA' ? <Sun className="h-8 w-8 text-white" /> :
                        casa.sigla === 'CASA IDOSO' ? <Home className="h-8 w-8 text-white" /> :
                        casa.sigla === 'CASA MULHER' ? <HeartPulse className="h-8 w-8 text-white" /> :
                        <Brain className="h-8 w-8 text-white" />
                      }
                      cor={
                        casa.sigla === 'CEMO' ? '#3b82f6' :
                        casa.sigla === 'CASA DIA' ? '#eab308' :
                        casa.sigla === 'CASA IDOSO' ? '#22c55e' :
                        casa.sigla === 'CASA MULHER' ? '#ec4899' :
                        '#a855f7'
                      }
                      metas={undefined}
                      secoes={casa.secoes}
                      badges={[casa.sigla, casa.tipo]}
                    />
                  ))}
                </div>
              </CollapsibleContent>
            </Collapsible>
          </TabsContent>

          {/* ABA 2: URGÊNCIA */}
          <TabsContent value="urgencia" className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold flex items-center gap-2" style={{ color: CORES_SAUDE_MUNICIPAL.urgencia }}>
                <AlertCircle className="h-5 w-5" />
                Unidades de Pronto Atendimento (UPA)
              </h2>
              <Badge style={{ backgroundColor: CORES_SAUDE_MUNICIPAL.urgencia }}>
                {UNIDADES_PRONTO_ATENDIMENTO.length} unidades
              </Badge>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {UNIDADES_PRONTO_ATENDIMENTO.map((upa) => (
                <CardUPA key={upa.id} upa={upa} />
              ))}
            </div>
          </TabsContent>

          {/* ABA 3: HOSPITAL */}
          <TabsContent value="hospital" className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold flex items-center gap-2" style={{ color: CORES_SAUDE_MUNICIPAL.hospital }}>
                <Building2 className="h-5 w-5" />
                Hospitais Municipais
              </h2>
              <Badge style={{ backgroundColor: CORES_SAUDE_MUNICIPAL.hospital }}>
                {HOSPITAIS_MUNICIPAIS.length} unidade
              </Badge>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {HOSPITAIS_MUNICIPAIS.map((hospital) => (
                <CardHospital key={hospital.id} hospital={hospital} />
              ))}
            </div>
          </TabsContent>

          {/* ABA 4: SERVIÇOS MÓVEIS */}
          <TabsContent value="moveis" className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold flex items-center gap-2" style={{ color: CORES_SAUDE_MUNICIPAL.movel }}>
                <Truck className="h-5 w-5" />
                Serviços Móveis de Saúde
              </h2>
              <Badge style={{ backgroundColor: CORES_SAUDE_MUNICIPAL.movel }}>
                {SERVICOS_MOVEIS.length} serviços
              </Badge>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {SERVICOS_MOVEIS.map((servico) => (
                <CardServicoMovel key={servico.id} servico={servico} />
              ))}
            </div>
          </TabsContent>
        </Tabs>

        {/* Footer */}
        <footer className="mt-8 pt-6 border-t text-center text-sm text-slate-500">
          <p style={{ color: CORES_SAUDE_MUNICIPAL.primaria }}>Sistema Único de Saúde - Gestão Municipal</p>
          <p>Todos os direitos reservados</p>
        </footer>
      </div>
    </main>
  );
}
